import { Actions } from '@app/actions/shared';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';

window.addEventListener('load', async () => {
  try {
    requestIdleCallback(() => {
      const openPopupLink = document.querySelector('#openExtension');

      if (openPopupLink instanceof HTMLElement) {
        openPopupLink?.addEventListener('click', handleClickOpenPopup);
      }
    });
  } catch (error) {
    console.error('error', error);
  }
});

async function handleClickOpenPopup(event: MouseEvent): Promise<void> {
  try {
    event.preventDefault();
    event.stopPropagation();

    await messageDispatcher.send({
      action: Actions.OpenPopupRoot,
    });
  } catch (error) {
    console.error(error);
  }
}
